const imgOriginal = "data:image/jpeg;base64,";
const imgShapes = "data:image/jpeg;base64,";
const imgGreyscale = "data:image/jpeg;base64,";
const imgLocalColors = "data:image/jpeg;base64,";
const imgGradients = "data:image/jpeg;base64,";
const imgLassoNoise = "data:image/jpeg;base64,";
const imgDetailBrush = "data:image/jpeg;base64,";
const imgThreshold = "data:image/jpeg;base64,";

// ── design tokens ────────────────────────────────────────────
const T = {
  oxblood: "#8b3a2f",
  paper: "#f5efe1",
  ink: "#1d1a15",
  inkSoft: "#5c554a",
  line: "#d8cfba",
  card: "#fbf7ec",
  mono: "'IBM Plex Mono', ui-monospace, monospace",
  serif: "'Newsreader', Georgia, serif",
};

// ── lesson data ──────────────────────────────────────────────
const STEPS = [
  {
    id: "study",
    label: "Study the Subject",
    img: imgOriginal,
    tool: "Reference · Eyes first",
    body:
      "Before a single stroke: read the photo. Three sandstone towers, a mid-ground ledge, a foreground slab. Ask where the light comes from (hard sun, camera-left) and which edges matter. Painting starts as observation, not rendering.",
    tip: "Squint. Whatever survives the squint is what you paint first.",
  },
  {
    id: "shapes",
    label: "Find the Shapes",
    img: imgShapes,
    tool: "Mental lasso · FG / MG / BG",
    body:
      "Carve the scene into three or four big overlapping shapes: background towers (BG), the mid-ground ledge (MG), the foreground slab (FG). Every shape gets its own layer later — this map is the whole composition.",
    tip: "If you can't outline it in red in your head, it's not a shape yet.",
  },
  {
    id: "greyscale",
    label: "Greyscale Block-Out",
    img: imgGreyscale,
    tool: "Lasso + Fill · one value per shape",
    body:
      "Fill each shape with a single flat value. Distance = lighter, foreground = darker. No texture, no edges — just value separation. If the read works in three greys, it will work in color. If it doesn't, no amount of detail will save it.",
    tip: "Atmospheric perspective is free depth: BG light, MG mid, FG dark.",
    deep:
      "These greys aren't just depth tags — they're budgets. Each plane gets a slice of the value range, and the nearest plane gets the widest slice. Since detail is just local value contrast, the value budget IS the detail budget: black = full contrast = full detail available; light grey = compressed contrast = suggestion only. The map never disappears in the color passes — it gets absorbed. Dark-near is the default (backlit scenes can invert it), but distinct, non-overlapping value bands per plane always holds.",
  },
  {
    id: "local",
    label: "Local Colors",
    img: imgLocalColors,
    tool: "Lock transparency · Fill",
    body:
      "Swap each grey for the object's local color — the color it 'is' before light does anything to it. Sky blue, sandstone browns. Lock each layer's transparent pixels so fills stay inside the silhouette.",
    tip: "Match the value of your grey when you pick the hue. Value carries; hue decorates.",
    deep:
      "It can look like the dark-to-light depth logic vanishes here — it doesn't. Depth starts being shared across channels: distant planes lose saturation and drift cool toward the sky, while values compress within each plane's band. Desaturate the finished painting and the block-out is still there underneath. (Prove it in the Value Budget lab below.)",
  },
  {
    id: "gradients",
    label: "Gradients Added",
    img: imgGradients,
    tool: "Gradient tool · G",
    body:
      "One linear gradient per shape turns flats into forms. Sky darkens toward the top, towers lighten toward the sun, ground planes shift warm-to-cool. Cheap, fast, and it establishes the lighting logic for everything after.",
    tip: "Gradient on a locked layer = instant plausible light. Ctrl/Cmd-click the layer thumbnail if you need a selection instead.",
  },
  {
    id: "lasso",
    label: "Lasso + Noisy Brush",
    img: imgLassoNoise,
    tool: "Lasso (L) + textured brush",
    body:
      "Lasso a region — a shadow pocket, a rock face — and scrub inside it with a noisy, textured brush. The selection keeps your edges crisp while the brush makes the interior gritty. Hard silhouette, broken interior: that's the rock look.",
    tip: "Selections are edge control. Brushes are surface control. Use both at once.",
  },
  {
    id: "detail",
    label: "More Detailed Brush",
    img: imgDetailBrush,
    tool: "Custom brushes · smaller, harder",
    body:
      "Now the smaller, harder, more characterful brushes: cracks, dark strata, cool bounce in the shadows. Detail goes only where the eye lands — the tower tops and the sunlit slab. Everything else stays a suggestion.",
    tip: "Detail is a spice, not a food group. Season the focal point.",
  },
];

// ── threshold canvas hook ────────────────────────────────────
function useThreshold(src, level, mode) {
  const canvasRef = useRef(null);
  const imgRef = useRef(null);

  const render = useCallback(() => {
    const canvas = canvasRef.current;
    const img = imgRef.current;
    if (!canvas || !img) return;
    const ctx = canvas.getContext("2d");
    canvas.width = img.naturalWidth;
    canvas.height = img.naturalHeight;
    ctx.drawImage(img, 0, 0);
    const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const p = data.data;
    for (let i = 0; i < p.length; i += 4) {
      const lum = 0.2126 * p[i] + 0.7152 * p[i + 1] + 0.0722 * p[i + 2];
      const isShadow = lum < level;
      // shadows mode: dark pixels → black stamp. highlights: bright → black stamp.
      const stamp = mode === "shadows" ? isShadow : !isShadow;
      const v = stamp ? 0 : 255;
      p[i] = p[i + 1] = p[i + 2] = v;
    }
    ctx.putImageData(data, 0, 0);
  }, [level, mode]);

  useEffect(() => {
    const img = new Image();
    img.src = src;
    img.onload = () => {
      imgRef.current = img;
      render();
    };
  }, [src]); // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => {
    render();
  }, [render]);

  return canvasRef;
}

// ── small ui pieces ──────────────────────────────────────────
function Eyebrow({ children }) {
  return (
    <div
      style={{
        fontFamily: T.mono,
        fontSize: 11,
        letterSpacing: "0.18em",
        textTransform: "uppercase",
        color: T.oxblood,
        marginBottom: 10,
      }}
    >
      {children}
    </div>
  );
}

function ToolChip({ children }) {
  return (
    <span
      style={{
        fontFamily: T.mono,
        fontSize: 11,
        color: T.paper,
        background: T.oxblood,
        padding: "4px 10px",
        borderRadius: 3,
        letterSpacing: "0.04em",
        display: "inline-block",
      }}
    >
      {children}
    </span>
  );
}

// ── main component ───────────────────────────────────────────
export default function BlockOutProcess() {
  const [step, setStep] = useState(0);
  const [level, setLevel] = useState(96);
  const [mode, setMode] = useState("shadows");
  const [sat, setSat] = useState(100);
  const canvasRef = useThreshold(imgOriginal, level, mode);
  const current = STEPS[step];

  // keyboard nav
  useEffect(() => {
    const onKey = (e) => {
      if (e.key === "ArrowRight") setStep((s) => Math.min(s + 1, STEPS.length - 1));
      if (e.key === "ArrowLeft") setStep((s) => Math.max(s - 1, 0));
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  return (
    <div
      style={{
        background: T.paper,
        color: T.ink,
        minHeight: "100vh",
        fontFamily: T.serif,
        padding: "48px 24px 96px",
      }}
    >
      <div style={{ maxWidth: 980, margin: "0 auto" }}>
        {/* header */}
        <header style={{ marginBottom: 40, borderBottom: `2px solid ${T.ink}`, paddingBottom: 24 }}>
          <Eyebrow>pLAtform · Digital Painting · Lesson</Eyebrow>
          <h1 style={{ fontSize: "clamp(32px, 5vw, 52px)", fontWeight: 500, lineHeight: 1.05, margin: 0 }}>
            The Block-Out Method
          </h1>
          <p style={{ fontFamily: T.mono, fontSize: 13, color: T.inkSoft, marginTop: 12, maxWidth: 620 }}>
            Big shapes → values → local color → gradients → texture → detail. Seven passes from photograph to painting, plus a threshold lab for mining shadow shapes.
          </p>
        </header>

        {/* step tabs */}
        <nav style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 24 }}>
          {STEPS.map((s, i) => {
            const active = i === step;
            return (
              <button
                key={s.id}
                onClick={() => setStep(i)}
                style={{
                  fontFamily: T.mono,
                  fontSize: 11,
                  letterSpacing: "0.03em",
                  padding: "8px 12px",
                  border: `1px solid ${active ? T.oxblood : T.line}`,
                  background: active ? T.oxblood : "transparent",
                  color: active ? T.paper : T.inkSoft,
                  borderRadius: 3,
                  cursor: "pointer",
                }}
              >
                {String(i + 1).padStart(2, "0")} {s.label}
              </button>
            );
          })}
        </nav>

        {/* step viewer */}
        <section
          style={{
            display: "grid",
            gridTemplateColumns: "minmax(280px, 440px) 1fr",
            gap: 32,
            alignItems: "start",
            background: T.card,
            border: `1px solid ${T.line}`,
            borderRadius: 6,
            padding: 28,
          }}
        >
          <figure style={{ margin: 0 }}>
            <img
              key={current.id}
              src={current.img}
              alt={current.label}
              style={{
                width: "100%",
                display: "block",
                borderRadius: 4,
                border: `1px solid ${T.line}`,
                animation: "bo-fade 240ms ease",
              }}
            />
            <figcaption style={{ fontFamily: T.mono, fontSize: 11, color: T.inkSoft, marginTop: 8 }}>
              fig. {step + 1}/{STEPS.length} — {current.label.toLowerCase()}
            </figcaption>
          </figure>

          <div>
            <Eyebrow>Step {String(step + 1).padStart(2, "0")}</Eyebrow>
            <h2 style={{ fontSize: 30, fontWeight: 500, margin: "0 0 12px" }}>{current.label}</h2>
            <div style={{ marginBottom: 16 }}>
              <ToolChip>{current.tool}</ToolChip>
            </div>
            <p style={{ fontSize: 17, lineHeight: 1.6, margin: "0 0 18px" }}>{current.body}</p>
            <div
              style={{
                borderLeft: `3px solid ${T.oxblood}`,
                paddingLeft: 14,
                fontFamily: T.mono,
                fontSize: 12.5,
                lineHeight: 1.6,
                color: T.inkSoft,
              }}
            >
              {current.tip}
            </div>

            {current.deep && (
              <div
                style={{
                  marginTop: 16,
                  background: T.paper,
                  border: `1px solid ${T.line}`,
                  borderRadius: 4,
                  padding: "14px 16px",
                }}
              >
                <div
                  style={{
                    fontFamily: T.mono,
                    fontSize: 10,
                    letterSpacing: "0.16em",
                    textTransform: "uppercase",
                    color: T.oxblood,
                    marginBottom: 6,
                  }}
                >
                  Theory · why this works
                </div>
                <p style={{ fontSize: 14.5, lineHeight: 1.6, margin: 0, color: T.ink }}>{current.deep}</p>
              </div>
            )}

            <div style={{ display: "flex", gap: 10, marginTop: 28 }}>
              <button
                onClick={() => setStep((s) => Math.max(s - 1, 0))}
                disabled={step === 0}
                style={navBtn(step === 0)}
              >
                ← Prev
              </button>
              <button
                onClick={() => setStep((s) => Math.min(s + 1, STEPS.length - 1))}
                disabled={step === STEPS.length - 1}
                style={navBtn(step === STEPS.length - 1)}
              >
                Next →
              </button>
              <span style={{ fontFamily: T.mono, fontSize: 11, color: T.inkSoft, alignSelf: "center" }}>
                ← / → keys work too
              </span>
            </div>
          </div>
        </section>

        {/* threshold lab */}
        <section style={{ marginTop: 64 }}>
          <Eyebrow>Lab · Image → Adjustments → Threshold</Eyebrow>
          <h2 style={{ fontSize: 34, fontWeight: 500, margin: "0 0 8px" }}>
            Mining Shadows &amp; Highlights for Brushes
          </h2>
          <p style={{ fontSize: 16, lineHeight: 1.6, maxWidth: 680, color: T.ink }}>
            Threshold forces every pixel to pure black or pure white around a single luminance level.
            Slide the level up and the <em>shadow shapes</em> of the subject emerge — the same shapes your
            noisy brush should be making. Flip the mode and you get the <em>highlight shapes</em> instead.
            Either map can be selected (Select → Color Range → Shadows) and turned into a stamp with
            Edit → Define Brush Preset.
          </p>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: 28,
              marginTop: 24,
              background: T.card,
              border: `1px solid ${T.line}`,
              borderRadius: 6,
              padding: 28,
            }}
          >
            {/* live canvas */}
            <div>
              <div style={{ fontFamily: T.mono, fontSize: 11, color: T.inkSoft, marginBottom: 8 }}>
                LIVE — threshold applied to the original photo
              </div>
              <canvas
                ref={canvasRef}
                style={{
                  width: "100%",
                  display: "block",
                  border: `1px solid ${T.line}`,
                  borderRadius: 4,
                  background: "#fff",
                }}
              />

              <div style={{ marginTop: 16 }}>
                <label
                  style={{
                    fontFamily: T.mono,
                    fontSize: 12,
                    display: "flex",
                    justifyContent: "space-between",
                    marginBottom: 6,
                  }}
                >
                  <span>Threshold level</span>
                  <span style={{ color: T.oxblood }}>{level}</span>
                </label>
                <input
                  type="range"
                  min={8}
                  max={248}
                  value={level}
                  onChange={(e) => setLevel(Number(e.target.value))}
                  style={{ width: "100%", accentColor: T.oxblood }}
                />
                <div style={{ display: "flex", gap: 8, marginTop: 12 }}>
                  {["shadows", "highlights"].map((m) => (
                    <button
                      key={m}
                      onClick={() => setMode(m)}
                      style={{
                        fontFamily: T.mono,
                        fontSize: 11,
                        padding: "7px 12px",
                        borderRadius: 3,
                        cursor: "pointer",
                        border: `1px solid ${mode === m ? T.oxblood : T.line}`,
                        background: mode === m ? T.oxblood : "transparent",
                        color: mode === m ? T.paper : T.inkSoft,
                      }}
                    >
                      isolate {m}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* reference + recipe */}
            <div>
              <div style={{ fontFamily: T.mono, fontSize: 11, color: T.inkSoft, marginBottom: 8 }}>
                REFERENCE — the target shadow map
              </div>
              <img
                src={imgThreshold}
                alt="Threshold shadows reference"
                style={{ width: "100%", display: "block", border: `1px solid ${T.line}`, borderRadius: 4 }}
              />
              <ol
                style={{
                  fontFamily: T.mono,
                  fontSize: 12.5,
                  lineHeight: 1.9,
                  color: T.ink,
                  paddingLeft: 20,
                  marginTop: 16,
                  marginBottom: 0,
                }}
              >
                <li>Duplicate the photo layer.</li>
                <li>Image → Adjustments → Threshold. Slide until only the crevice shadows read.</li>
                <li>Select → Color Range → Shadows (or Magic Wand the black).</li>
                <li>Copy a patch of shapes to a new doc on white.</li>
                <li>Edit → Define Brush Preset — a rock-shadow stamp, harvested from the subject itself.</li>
              </ol>
            </div>
          </div>
        </section>

        {/* value budget lab */}
        <section style={{ marginTop: 64 }}>
          <Eyebrow>Lab · The Value Budget</Eyebrow>
          <h2 style={{ fontSize: 34, fontWeight: 500, margin: "0 0 8px" }}>
            The Block-Out Never Leaves
          </h2>
          <p style={{ fontSize: 16, lineHeight: 1.6, maxWidth: 680, color: T.ink }}>
            Drag the slider to drain the color out of the finished render. The greyscale block-out is
            still in there — softer, because gradients and light have moved values around <em>within</em>{" "}
            each plane's band, but the plane separation survives. Value carries depth; hue and
            saturation were layered on top of it, not swapped in for it.
          </p>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: 28,
              marginTop: 24,
              background: T.card,
              border: `1px solid ${T.line}`,
              borderRadius: 6,
              padding: 28,
            }}
          >
            <div>
              <div style={{ fontFamily: T.mono, fontSize: 11, color: T.inkSoft, marginBottom: 8 }}>
                LIVE — final render, saturation {sat}%
              </div>
              <img
                src={imgDetailBrush}
                alt="Final render with adjustable saturation"
                style={{
                  width: "100%",
                  display: "block",
                  border: `1px solid ${T.line}`,
                  borderRadius: 4,
                  filter: `saturate(${sat}%)`,
                  transition: "filter 80ms linear",
                }}
              />
              <label
                style={{
                  fontFamily: T.mono,
                  fontSize: 12,
                  display: "flex",
                  justifyContent: "space-between",
                  margin: "14px 0 6px",
                }}
              >
                <span>color ← → greyscale</span>
                <span style={{ color: T.oxblood }}>{sat}%</span>
              </label>
              <input
                type="range"
                min={0}
                max={100}
                value={sat}
                onChange={(e) => setSat(Number(e.target.value))}
                style={{ width: "100%", accentColor: T.oxblood }}
              />
            </div>

            <div>
              <div style={{ fontFamily: T.mono, fontSize: 11, color: T.inkSoft, marginBottom: 8 }}>
                REFERENCE — the original value budget
              </div>
              <img
                src={imgGreyscale}
                alt="Greyscale block-out reference"
                style={{ width: "100%", display: "block", border: `1px solid ${T.line}`, borderRadius: 4 }}
              />
              <div
                style={{
                  borderLeft: `3px solid ${T.oxblood}`,
                  paddingLeft: 14,
                  marginTop: 16,
                  fontFamily: T.mono,
                  fontSize: 12.5,
                  lineHeight: 1.7,
                  color: T.inkSoft,
                }}
              >
                Read the drained render against the block-out: each plane still lives inside the value
                band it was assigned. The widest band (foreground) is where all the detail landed —
                because detail is local value contrast, and contrast is what that band bought.
              </div>
            </div>
          </div>
        </section>

        <footer
          style={{
            marginTop: 56,
            paddingTop: 16,
            borderTop: `1px solid ${T.line}`,
            fontFamily: T.mono,
            fontSize: 11,
            color: T.inkSoft,
            display: "flex",
            justifyContent: "space-between",
          }}
        >
          <span>pLAtform / digital painting / block-out method</span>
          <span>value first · edges second · detail last</span>
        </footer>
      </div>

      <style>{`
        @keyframes bo-fade { from { opacity: 0; transform: translateY(4px); } to { opacity: 1; transform: none; } }
        @media (max-width: 760px) {
          section { grid-template-columns: 1fr !important; }
        }
      `}</style>
    </div>
  );
}

function navBtn(disabled) {
  return {
    fontFamily: T.mono,
    fontSize: 12,
    padding: "9px 16px",
    borderRadius: 3,
    border: `1px solid ${disabled ? T.line : T.ink}`,
    background: "transparent",
    color: disabled ? T.line : T.ink,
    cursor: disabled ? "default" : "pointer",
  };
}
